 1	import React, { FC } from 'react';
 2	
 3	import { modelToGroupVersionKind, NamespaceModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiNetworkingV1NetworkPolicy } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import {
 6	  ResourceLink,
 7	  Timestamp,
 8	  useAccessReview,
 9	  useAnnotationsModal,
10	  useLabelsModal,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { DetailsItem } from '@utils/components/DetailsItem/DetailsItem';
13	import { LabelList } from '@utils/components/DetailsItem/LabelList';
14	import { OwnerReferences } from '@utils/components/OwnerReference/owner-references';
15	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
16	import { getPolicyModel } from '@utils/resources/networkpolicies/utils';
17	
18	type NetworkPolicyDetailsMetadataProps = {
19	  networkPolicy: IoK8sApiNetworkingV1NetworkPolicy;
20	};
21	
22	const NetworkPolicyDetailsMetadata: FC<NetworkPolicyDetailsMetadataProps> = ({ networkPolicy }) => {
23	  const { t } = useNetworkingTranslation();
24	
25	  const policyModel = getPolicyModel(networkPolicy);
26	
27	  const metadata = networkPolicy?.metadata;
28	  const annotationsModalLauncher = useAnnotationsModal(networkPolicy);
29	  const labelsModalLauncher = useLabelsModal(networkPolicy);
30	
31	  const [canUpdate] = useAccessReview({
32	    group: policyModel?.apiGroup,
33	    name: metadata?.name,
34	    namespace: metadata?.namespace,
35	    resource: policyModel?.plural,
36	    verb: 'patch',
37	  });
38	
39	  return (
40	    <>
41	      <DetailsItem label={t('Name')} obj={networkPolicy} path={'metadata.name'} />
42	      <DetailsItem label={t('Namespace')} obj={networkPolicy} path="metadata.namespace">
43	        <ResourceLink
44	          groupVersionKind={modelToGroupVersionKind(NamespaceModel)}
45	          name={metadata.namespace}
46	        />
47	      </DetailsItem>
48	      <DetailsItem
49	        canEdit={canUpdate}
50	        editAsGroup
51	        label={t('Labels')}
52	        obj={networkPolicy}
53	        onEdit={labelsModalLauncher}
54	        path="metadata.labels"
55	      >
56	        <LabelList
57	          groupVersionKind={modelToGroupVersionKind(policyModel)}
58	          labels={metadata?.labels}
59	        />
60	      </DetailsItem>
61	      <DetailsItem
62	        canEdit={canUpdate}
63	        label={t('Annotations')}
64	        obj={networkPolicy}
65	        onEdit={annotationsModalLauncher}
66	        path="metadata.annotations"
67	      >
68	        {t('{{count}} annotation', {
69	          count: Object.keys(metadata?.annotations || {}).length,
70	        })}
71	      </DetailsItem>
72	      <DetailsItem label={t('Created at')} obj={networkPolicy} path="metadata.creationTimestamp">
73	        <Timestamp timestamp={metadata?.creationTimestamp} />
74	      </DetailsItem>
75	      <DetailsItem label={t('Owner')} obj={networkPolicy} path="metadata.ownerReferences">
76	        <OwnerReferences resource={networkPolicy} />
77	      </DetailsItem>
78	    </>
79	  );
80	};
81	
82	export default NetworkPolicyDetailsMetadata;

